-- ============================================================================
-- One-time data import: MICHALI's expenses (Jan-Jul 2026), from
-- MICHALI_2_Expenses.pdf. DATA only, not a schema change. Safe to re-run:
-- deletes any prior run of this exact script (matched by boat_id + a marker
-- in notes) before re-inserting.
--
-- RUN ORDER: run this file BEFORE 2026-07-michali-bank-cash-detail.sql - that
-- script's catch-all calculation sums these expenses by payment method, so it
-- needs to run after they're already in.
--
-- Flagged, not guessed - all entered with category 'other' so they're easy to
-- find afterward by filtering the Expenses list to category "Other":
--   - 16 rows where the source sheet's own "EXPENSE DESCRIPTION" is just "?"
--     (13 rows on 26 Mar, 4 rows on 23 Mar, 1 row on 2 Jun) - description kept
--     literally as "?" plus the original PLN amount noted, nothing guessed.
--   - 8 rows with a description but no "TYPE OF EXPENSE" at all in the source
--     sheet: "Dinner MYS" (x2, 23 Mar), "Tsafrir expenses" (23 Mar),
--     "Officesupplies" (18 Mar), "MediaMarkt Homesupplies" (18 Mar),
--     "Dyson Vacuumer" (18 Mar), "Fuel Car" (12 Mar), "EPIRB for Sunreef"
--     (5 Mar).
--   - 1 row ("Amazon Fire TV Stick 4K Gen2 Wi-Fi 6", 27 May, EUR39.80) has
--     NEITHER a category nor a payment method in the source sheet - payment
--     method defaulted to 'card' (a guess, unlike everything else here) since
--     that's what every other unlabeled item purchase in this ledger turned
--     out to be. Please verify this one specifically.
--
-- Not entered separately: the Cash_Flow.pdf sheet's own "CARD" rows (cash
-- withdrawals) - those are in 2026-07-michali-bank-cash-detail.sql instead,
-- since they're cash-ledger movements, not expenses.
-- ============================================================================

do $$
declare
  v_boat_id uuid;
  v_marker text := 'michali-expenses-2026-import';
begin
  select id into v_boat_id from public.boats where lower(trim(name)) = 'michali';
  if v_boat_id is null then
    raise exception 'Boat "Michali" not found (matched on lower(trim(name)) = ''michali'') - check the exact boat name in the boats table and adjust this script before running it.';
  end if;

  delete from public.expenses where boat_id = v_boat_id and notes = v_marker;

end $$;
